# ══════════════════════════════════════════════════════════════════════════
#  ICON HELPERS
# ══════════════════════════════════════════════════════════════════════════
def make_icon(size=32) -> "QIcon":
    try:
        raw = base64.b64decode(ICON_B64.get(size, ICON_B64[32]))
        pm = QPixmap(); pm.loadFromData(raw)
        return QIcon(pm)
    except Exception:
        return QIcon()

def make_pixmap(size=64) -> "QPixmap":
    try:
        raw = base64.b64decode(ICON_B64.get(size, ICON_B64[64]))
        pm = QPixmap(); pm.loadFromData(raw)
        return pm
    except Exception:
        return QPixmap()


# ══════════════════════════════════════════════════════════════════════════
#  AUDIO ENGINE
# ══════════════════════════════════════════════════════════════════════════
class AudioSignals(QObject):
    level_changed = pyqtSignal(float)

class AudioEngine:
    def __init__(self):
        self.frames     = []
        self.recording  = False
        self.paused     = False
        self._stream    = None
        self._lock      = threading.Lock()
        self.peak_level = 0.0

    def _callback(self, indata, frames, time_info, status):
        if self.recording and not self.paused:
            chunk = indata.copy()
            with self._lock:
                self.frames.append(chunk)
            rms = float(np.sqrt(np.mean(chunk.astype(np.float32) ** 2)))
            self.peak_level = min(rms / 8000.0, 1.0)

    def start(self):
        if not AUDIO_AVAILABLE:
            return False
        self.frames = []; self.recording = True
        self.paused = False; self.peak_level = 0.0
        try:
            self._stream = sd.InputStream(
                samplerate=SAMPLE_RATE, channels=CHANNELS,
                dtype=DTYPE, blocksize=CHUNK, callback=self._callback)
            self._stream.start(); return True
        except Exception as exc:
            self.recording = False
            raise RuntimeError(str(exc)) from exc

    def pause(self):  self.paused = True;  self.peak_level = 0.0
    def resume(self): self.paused = False

    def stop(self):
        self.recording = False; self.peak_level = 0.0
        if self._stream:
            self._stream.stop(); self._stream.close(); self._stream = None

    def save(self, path: str) -> bool:
        with self._lock:
            if not self.frames: return False
            data = np.concatenate(self.frames, axis=0)
        with wave.open(path, "wb") as wf:
            wf.setnchannels(CHANNELS); wf.setsampwidth(2)
            wf.setframerate(SAMPLE_RATE); wf.writeframes(data.tobytes())
        return True

    @property
    def duration(self):
        with self._lock:
            return sum(len(f) for f in self.frames) / SAMPLE_RATE


# ══════════════════════════════════════════════════════════════════════════
#  VU METER  — colours driven by theme
# ══════════════════════════════════════════════════════════════════════════
class VUMeter(QWidget):
    BARS = 30

    def __init__(self, theme: dict, parent=None):
        super().__init__(parent)
        self._level = 0.0
        self._theme = theme
        self.setFixedHeight(28)
        self.setMinimumWidth(200)
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)

    def set_theme(self, theme: dict):
        self._theme = theme
        self.update()

    def set_level(self, level: float):
        self._level = max(0.0, min(1.0, level)); self.update()

    def paintEvent(self, event):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        t   = self._theme
        w   = self.width()
        h   = self.height()
        bw  = (w - (self.BARS + 1) * 2) / self.BARS
        act = int(self._level * self.BARS)
        for i in range(self.BARS):
            x = 2 + i * (bw + 2)
            if i < act:
                frac = i / self.BARS
                col  = QColor(t["green"] if frac < 0.6 else (t["amber"] if frac < 0.85 else t["accent"]))
            else:
                col  = QColor(t["border"])
            p.fillRect(int(x), 4, max(1, int(bw)), h - 8, col)


