#  RECORDING CARD
# ══════════════════════════════════════════════════════════════════════════
class RecordingCard(QFrame):
    deleted = pyqtSignal(object)

    def __init__(self, name: str, duration: float, path: str,
                 theme: dict, parent=None):
        super().__init__(parent)
        self.path = path
        t = theme
        self.setStyleSheet(f"""
            QFrame {{ background:{t['card']}; border-radius:6px; border:1px solid {t['border']}; }}
        """)
        layout = QHBoxLayout(self)
        layout.setContentsMargins(12, 8, 12, 8)

        icon_lbl = QLabel("🎙")
        icon_lbl.setStyleSheet(f"color:{t['accent']}; font-size:18px; border:none;")
        layout.addWidget(icon_lbl)

        info = QVBoxLayout(); info.setSpacing(2)
        name_lbl = QLabel(name)
        name_lbl.setStyleSheet(
            f"color:{t['text']}; font-family:Consolas; font-size:10pt; font-weight:bold; border:none;")
        dur_str  = time.strftime("%M:%S", time.gmtime(duration))
        size_str = self._fsize(path)
        meta_lbl = QLabel(f"{dur_str}  ·  {size_str}  ·  {path}")
        meta_lbl.setStyleSheet(
            f"color:{t['text_dim']}; font-family:Consolas; font-size:8pt; border:none;")
        info.addWidget(name_lbl); info.addWidget(meta_lbl)
        layout.addLayout(info, 1)

        del_btn = QPushButton("✕")
        del_btn.setFixedSize(28, 28)
        del_btn.setStyleSheet(f"""
            QPushButton {{ background:transparent; color:{t['text_dim']}; border:none; font-size:13px; border-radius:4px; }}
            QPushButton:hover {{ color:{t['accent']}; background:{t['border']}; }}
        """)
        del_btn.clicked.connect(lambda: self.deleted.emit(self))
        layout.addWidget(del_btn)

    @staticmethod
    def _fsize(path):
        try:
            b = os.path.getsize(path)
            return f"{b/1024:.1f} KB" if b < 1_048_576 else f"{b/1_048_576:.2f} MB"
        except OSError:
            return "—"


