#  LANGUAGE TOGGLE SWITCH  (EN | PL)
# ══════════════════════════════════════════════════════════════════════════
class LangToggle(QWidget):
    """Sliding pill toggle: EN ←→ PL"""
    lang_changed = pyqtSignal(str)

    def __init__(self, initial_lang: str = "en", parent=None):
        super().__init__(parent)
        self._lang = initial_lang
        self.setFixedSize(68, 24)
        self.setCursor(Qt.CursorShape.PointingHandCursor)
        self.setToolTip("Switch language / Zmień język")

    def set_lang(self, lang: str):
        self._lang = lang
        self.update()

    def mousePressEvent(self, event):
        self._lang = "pl" if self._lang == "en" else "en"
        self.update()
        self.lang_changed.emit(self._lang)

    def paintEvent(self, event):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        W, H = self.width(), self.height()
        R = H // 2

        # track background
        track_col = QColor("#3a3a3a")
        p.setBrush(track_col); p.setPen(Qt.PenStyle.NoPen)
        p.drawRoundedRect(0, 0, W, H, R, R)

        # labels
        p.setFont(QFont("Consolas", 8, QFont.Weight.Bold))
        # EN label
        en_col = QColor("#ffffff") if self._lang == "en" else QColor("#666666")
        p.setPen(en_col)
        p.drawText(4, 0, W//2 - 2, H, Qt.AlignmentFlag.AlignCenter, "EN")
        # PL label
        pl_col = QColor("#ffffff") if self._lang == "pl" else QColor("#666666")
        p.setPen(pl_col)
        p.drawText(W//2, 0, W//2 - 2, H, Qt.AlignmentFlag.AlignCenter, "PL")

        # sliding pill
        pill_x = 2 if self._lang == "en" else W // 2
        p.setBrush(QColor("#ff3c3c")); p.setPen(Qt.PenStyle.NoPen)
        p.drawRoundedRect(pill_x, 2, W//2 - 2, H - 4, R - 2, R - 2)

        # labels on pill (white)
        p.setFont(QFont("Consolas", 8, QFont.Weight.Bold))
        p.setPen(QColor("#ffffff"))
        if self._lang == "en":
            p.drawText(pill_x, 0, W//2 - 2, H, Qt.AlignmentFlag.AlignCenter, "EN")
        else:
            p.drawText(pill_x, 0, W//2 - 2, H, Qt.AlignmentFlag.AlignCenter, "PL")


