#  MAIN WINDOW
# ══════════════════════════════════════════════════════════════════════════
class MainWindow(QMainWindow):
    IDLE = "idle"; REC = "recording"; PAU = "paused"

    def __init__(self):
        super().__init__()
        self._lang       = "en"
        self._theme_name = THEME_NAMES[0]
        self._theme      = THEMES[self._theme_name]
        self._engine     = AudioEngine()
        self._state      = self.IDLE
        self._start_ts   = 0.0
        self._elapsed    = 0.0
        self._cards      = []
        self._compact    = False
        self._save_dir   = os.path.join(os.path.expanduser("~"),
                                        STRINGS[self._lang]["save_dir"])
        os.makedirs(self._save_dir, exist_ok=True)
        self.setWindowIcon(make_icon(256))
        self._build_ui()
        self._apply_theme()
        self._update_texts()
        self._refresh()

        self._timer = QTimer(self)
        self._timer.setInterval(50)
        self._timer.timeout.connect(self._tick)

        if not AUDIO_AVAILABLE:
            QTimer.singleShot(400, self._hint)

    # ── UI BUILD ────────────────────────────────────────────────────────────
    def _build_ui(self):
        self.setFixedSize(480, 740)
        central = QWidget(); self.setCentralWidget(central)
        root = QVBoxLayout(central)
        root.setContentsMargins(0,0,0,0); root.setSpacing(0)

        # ── top bar ──────────────────────────────────────────────────────
        topbar = QFrame(); topbar.setObjectName("topbar"); topbar.setFixedHeight(34)
        tb = QHBoxLayout(topbar); tb.setContentsMargins(10,0,10,0); tb.setSpacing(4)

        # LEFT — Compact + Topmost
        self._compact_btn = QPushButton("⊟")
        self._compact_btn.setObjectName("topbtn")
        self._compact_btn.setFixedSize(26, 26)
        self._compact_btn.setCheckable(True)
        self._compact_btn.setToolTip("Compact mode / Tryb kompaktowy")
        self._compact_btn.clicked.connect(self._toggle_compact)
        tb.addWidget(self._compact_btn)

        self._topmost_btn = QPushButton("📌")
        self._topmost_btn.setObjectName("topbtn")
        self._topmost_btn.setFixedSize(26, 26)
        self._topmost_btn.setToolTip("Always on top / Zawsze na wierzchu")
        self._topmost_btn.setCheckable(True)
        self._topmost_btn.clicked.connect(self._toggle_topmost)
        tb.addWidget(self._topmost_btn)

        # CENTRE — Theme combo (expands to fill)
        tb.addStretch(1)
        self._theme_combo = QComboBox()
        self._theme_combo.setObjectName("themeCombo")
        self._theme_combo.addItems(THEME_NAMES)
        self._theme_combo.setCurrentText(self._theme_name)
        self._theme_combo.currentTextChanged.connect(self._change_theme)
        self._theme_combo.setFixedHeight(22)
        self._theme_combo.setMinimumWidth(160)
        tb.addWidget(self._theme_combo)
        tb.addStretch(1)

        # RIGHT — About + Language toggle
        self._about_btn = QPushButton("ℹ")
        self._about_btn.setObjectName("topbtn")
        self._about_btn.setFixedSize(26, 26)
        self._about_btn.setToolTip("About / O programie")
        self._about_btn.clicked.connect(self._show_about)
        tb.addWidget(self._about_btn)

        self._lang_toggle = LangToggle(self._lang)
        self._lang_toggle.lang_changed.connect(self._on_lang_changed)
        tb.addWidget(self._lang_toggle)

        root.addWidget(topbar)

        # ── header ───────────────────────────────────────────────────────
        hdr = QFrame(); hdr.setObjectName("header")
        hl  = QVBoxLayout(hdr); hl.setAlignment(Qt.AlignmentFlag.AlignCenter)
        hl.setContentsMargins(0,10,0,10)
        self._hdr_icon = QLabel(); self._hdr_icon.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self._hdr_icon.setStyleSheet("border:none; background:transparent;")
        pm = make_pixmap(40)
        if not pm.isNull():
            self._hdr_icon.setPixmap(pm.scaled(36,36,
                Qt.AspectRatioMode.KeepAspectRatio,
                Qt.TransformationMode.SmoothTransformation))
        hl.addWidget(self._hdr_icon)
        self._title_lbl    = QLabel(); self._title_lbl.setObjectName("appTitle")
        self._title_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter); hl.addWidget(self._title_lbl)
        self._subtitle_lbl = QLabel(); self._subtitle_lbl.setObjectName("appSubtitle")
        self._subtitle_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter); hl.addWidget(self._subtitle_lbl)
        root.addWidget(hdr)
        self._hdr_frame = hdr

        # ── timer ────────────────────────────────────────────────────────
        tf = QFrame(); tf.setObjectName("timerFrame")
        tl = QVBoxLayout(tf); tl.setAlignment(Qt.AlignmentFlag.AlignCenter)
        tl.setContentsMargins(0,16,0,10)
        self._time_lbl   = QLabel("00:00:00"); self._time_lbl.setObjectName("timerLabel")
        self._time_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter); tl.addWidget(self._time_lbl)
        self._status_lbl = QLabel(); self._status_lbl.setObjectName("statusLabel")
        self._status_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter); tl.addWidget(self._status_lbl)
        root.addWidget(tf)
        self._timer_frame = tf

        # ── vu ───────────────────────────────────────────────────────────
        vu_wrap = QFrame(); vu_wrap.setObjectName("vuWrap")
        vul = QHBoxLayout(vu_wrap); vul.setContentsMargins(24,0,24,10)
        self._vu = VUMeter(self._theme); vul.addWidget(self._vu)
        root.addWidget(vu_wrap)
        self._vu_frame = vu_wrap

        # ── buttons ──────────────────────────────────────────────────────
        bf = QFrame(); bf.setObjectName("btnFrame")
        bl = QHBoxLayout(bf); bl.setContentsMargins(16,6,16,6); bl.setSpacing(8)
        self._btn_rec = QPushButton(); self._btn_rec.setObjectName("btnRec")
        self._btn_rec.setFixedHeight(42); self._btn_rec.clicked.connect(self._toggle_rec)
        self._btn_pau = QPushButton(); self._btn_pau.setObjectName("btnPau")
        self._btn_pau.setFixedHeight(42); self._btn_pau.setEnabled(False)
        self._btn_pau.clicked.connect(self._toggle_pause)
        self._btn_sav = QPushButton(); self._btn_sav.setObjectName("btnSav")
        self._btn_sav.setFixedHeight(42); self._btn_sav.setEnabled(False)
        self._btn_sav.clicked.connect(self._save)
        for b in (self._btn_rec, self._btn_pau, self._btn_sav):
            b.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
            bl.addWidget(b)
        root.addWidget(bf)
        self._btn_frame = bf

        # ── folder ───────────────────────────────────────────────────────
        self._dir_lbl = QLabel(); self._dir_lbl.setObjectName("dirLabel")
        self._dir_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter); root.addWidget(self._dir_lbl)

        # ── separator + list header ──────────────────────────────────────
        self._sep = QFrame(); self._sep.setFrameShape(QFrame.Shape.HLine)
        self._sep.setObjectName("mainSep"); root.addWidget(self._sep)
        self._list_hdr = QLabel(); self._list_hdr.setObjectName("listHdr")
        self._list_hdr.setContentsMargins(20,2,0,4); root.addWidget(self._list_hdr)

        # ── scroll list ──────────────────────────────────────────────────
        self._scroll = QScrollArea(); self._scroll.setWidgetResizable(True)
        self._scroll.setObjectName("scrollArea")
        self._list_widget = QWidget(); self._list_widget.setObjectName("listWidget")
        self._list_layout = QVBoxLayout(self._list_widget)
        self._list_layout.setContentsMargins(8,4,8,4); self._list_layout.setSpacing(6)
        self._list_layout.addStretch()
        self._scroll.setWidget(self._list_widget); root.addWidget(self._scroll, 1)
        self._scroll_ref = self._scroll

        # ── footer ───────────────────────────────────────────────────────
        footer = QFrame(); footer.setObjectName("footer")
        fl = QVBoxLayout(footer); fl.setContentsMargins(0,5,0,5); fl.setSpacing(1)
        self._fmt_lbl = QLabel(); self._fmt_lbl.setObjectName("fmtLabel")
        self._fmt_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter); fl.addWidget(self._fmt_lbl)
        copy_lbl = QLabel(__copyright__); copy_lbl.setObjectName("copyLabel")
        copy_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter); fl.addWidget(copy_lbl)
        root.addWidget(footer)
        self._footer_frame = footer

    # ── COMPACT MODE ────────────────────────────────────────────────────────
    def _toggle_compact(self, checked: bool):
        self._compact = checked
        t = self._theme

        # widgets hidden in compact mode
        hidden = [
            self._hdr_frame,
            self._dir_lbl,
            self._sep,
            self._list_hdr,
            self._scroll_ref,
            self._footer_frame,
        ]
        for w in hidden:
            w.setVisible(not checked)

        if checked:
            # compact: show only topbar + timer + vu + buttons
            self._compact_btn.setText("⊞")
            self._compact_btn.setStyleSheet(
                f"QPushButton {{ background:{t['accent']}; color:white; border:none; "
                f"border-radius:4px; font-size:13px; }}")
            # shrink timer font
            self._time_lbl.setStyleSheet(
                f"color:{t['text']}; font-family:Courier New; font-size:26pt; font-weight:bold;")
            new_h = (
                34  +   # topbar
                68  +   # timer (smaller)
                40  +   # vu
                60  +   # buttons
                8       # padding
            )
            self.setFixedSize(480, new_h)
        else:
            # restore full mode
            self._compact_btn.setText("⊟")
            self._compact_btn.setStyleSheet("")
            self._time_lbl.setStyleSheet(
                f"color:{t['text']}; font-family:Courier New; font-size:38pt; font-weight:bold;")
            self.setFixedSize(480, 740)

        # ── THEME ────────────────────────────────────────────────────────────────
    def _change_theme(self, name: str):
        self._theme_name = name
        self._theme = THEMES[name]
        self._vu.set_theme(self._theme)
        self._apply_theme()
        self._refresh()
        # re-apply compact highlight if active
        if self._compact:
            t = self._theme
            self._compact_btn.setStyleSheet(
                f"QPushButton {{ background:{t['accent']}; color:white; border:none; "
                f"border-radius:4px; font-size:13px; }}")
            self._time_lbl.setStyleSheet(
                f"color:{t['text']}; font-family:Courier New; font-size:26pt; font-weight:bold;")

    def _apply_theme(self):
        t = self._theme
        font_base = "font-family:Consolas; font-size:9pt;"
        font_mono = "font-family:Courier New;"

        self.setStyleSheet(f"""
            QMainWindow, QWidget {{ background:{t['bg']}; color:{t['text']}; }}

            QFrame#topbar  {{ background:{t['panel']}; border-bottom:1px solid {t['border']}; }}

            QComboBox#themeCombo {{
                background:{t['card']}; color:{t['text']}; border:1px solid {t['border']};
                border-radius:3px; padding:0 6px; {font_base}
            }}
            QComboBox#themeCombo::drop-down {{ border:none; width:18px; }}
            QComboBox#themeCombo QAbstractItemView {{
                background:{t['card']}; color:{t['text']}; border:1px solid {t['border']};
                selection-background-color:{t['border']};
            }}

            QPushButton#topbtn {{
                background:transparent; color:{t['text_dim']}; border:none;
                {font_base} padding:2px 8px;
            }}
            QPushButton#topbtn:hover {{ color:{t['text']}; }}

            QFrame#header  {{ background:{t['panel']}; border-bottom:1px solid {t['border']}; }}
            QLabel#appTitle    {{ color:{t['text']}; {font_mono} font-size:14pt; font-weight:bold; }}
            QLabel#appSubtitle {{ color:{t['text_dim']}; {font_mono} font-size:8pt; }}

            QFrame#timerFrame  {{ background:{t['bg']}; }}
            QLabel#timerLabel  {{ color:{t['text']}; {font_mono} font-size:38pt; font-weight:bold; }}
            QLabel#statusLabel {{ {font_mono} font-size:10pt; }}

            QFrame#vuWrap   {{ background:{t['bg']}; }}
            QFrame#btnFrame {{ background:{t['bg']}; }}

            QLabel#dirLabel {{ color:{t['text_dim']}; {font_base} padding:3px 0; }}
            QFrame#mainSep  {{ color:{t['border']}; margin:4px 16px; }}
            QLabel#listHdr  {{ color:{t['text_dim']}; {font_mono} font-size:8pt; font-weight:bold; }}

            QScrollArea#scrollArea {{ border:none; background:{t['bg']}; }}
            QWidget#listWidget     {{ background:{t['bg']}; }}
            QScrollBar:vertical    {{ background:{t['bg']}; width:6px; }}
            QScrollBar::handle:vertical {{ background:{t['border']}; border-radius:3px; }}
            QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {{ height:0; }}

            QFrame#footer   {{ background:{t['panel']}; border-top:1px solid {t['border']}; }}
            QLabel#fmtLabel {{ color:{t['text_dim']}; {font_base} font-size:7pt; }}
            QLabel#copyLabel {{ color:{t['border']}; {font_base} font-size:6pt; }}
        """)
        # style buttons via _refresh (they carry state-dependent colours)

    def _btn_style(self, bg, color, border=None, hover_bg=None):
        bdr = border or color
        hvr = hover_bg or bg
        return f"""
            QPushButton {{ background:{bg}; color:{color}; border:1px solid {bdr};
                          border-radius:5px; font-family:Courier New; font-size:9pt; font-weight:bold; }}
            QPushButton:hover:enabled {{ background:{hvr}; }}
            QPushButton:disabled {{ color:{self._theme['border']}; border-color:{self._theme['card']};
                                    background:{self._theme['card']}; }}
        """

    # ── TEXTS ────────────────────────────────────────────────────────────────
    def _update_texts(self):
        s = STRINGS[self._lang]
        self.setWindowTitle(s["app_title"])
        self._title_lbl.setText(f"◉  {s['app_title'].upper()}")
        self._subtitle_lbl.setText(s["app_subtitle"])
        self._dir_lbl.setText(f"📁 {self._save_dir}")
        self._list_hdr.setText(s["label_recordings"])
        self._fmt_lbl.setText(s["label_format"])

    # ── LANG ─────────────────────────────────────────────────────────────────
    def _on_lang_changed(self, lang: str):
        self._lang = lang
        self._save_dir = os.path.join(os.path.expanduser("~"),
                                      STRINGS[self._lang]["save_dir"])
        os.makedirs(self._save_dir, exist_ok=True)
        self._update_texts()
        self._refresh()

    # kept for compatibility
    def _switch_lang(self):
        new_lang = "en" if self._lang == "pl" else "pl"
        self._on_lang_changed(new_lang)

    def _toggle_topmost(self, checked: bool):
        flags = self.windowFlags()
        if checked:
            self.setWindowFlags(flags | Qt.WindowType.WindowStaysOnTopHint)
            self._topmost_btn.setStyleSheet(
                f"QPushButton {{ background:{self._theme['accent']}; color:white; border:none; border-radius:4px; font-size:13px; }}")
        else:
            self.setWindowFlags(flags & ~Qt.WindowType.WindowStaysOnTopHint)
            self._topmost_btn.setStyleSheet("")
        self.show()

    def _show_about(self):
        AboutDialog(self, self._lang, self._theme).exec()

    # ── RECORDING ────────────────────────────────────────────────────────────
    def _toggle_rec(self):
        if self._state == self.IDLE:
            if not AUDIO_AVAILABLE: self._hint(); return
            try: self._engine.start()
            except RuntimeError as exc:
                QMessageBox.critical(self, STRINGS[self._lang]["dlg_mic_title"], str(exc)); return
            self._state = self.REC; self._start_ts = time.time()
            self._elapsed = 0.0; self._timer.start()
        else:
            self._engine.stop(); self._timer.stop()
            self._state = self.IDLE; self._elapsed = 0.0
            self._time_lbl.setText("00:00:00"); self._vu.set_level(0.0)
        self._refresh()

    def _toggle_pause(self):
        if self._state == self.REC:
            self._elapsed += time.time() - self._start_ts
            self._engine.pause(); self._timer.stop(); self._state = self.PAU
        elif self._state == self.PAU:
            self._start_ts = time.time()
            self._engine.resume(); self._timer.start(); self._state = self.REC
        self._refresh()

    def _save(self):
        if self._state not in (self.REC, self.PAU): return
        if self._state == self.REC:
            self._elapsed += time.time() - self._start_ts
        self._engine.stop(); self._timer.stop()
        self._state = self.IDLE; self._vu.set_level(0.0)

        s  = STRINGS[self._lang]
        ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        default = os.path.join(self._save_dir, f"{s['dlg_save_prefix']}_{ts}.wav")
        path, _ = QFileDialog.getSaveFileName(
            self, s["dlg_save_title"], default, s["dlg_save_filter"])
        if path:
            if self._engine.save(path):
                self._add_card(os.path.basename(path), self._elapsed, path)
                QMessageBox.information(self, s["dlg_saved_title"],
                                        s["dlg_saved_msg"].format(path))
            else:
                QMessageBox.warning(self, s["dlg_empty_title"], s["dlg_empty_msg"])
        self._elapsed = 0.0; self._time_lbl.setText("00:00:00"); self._refresh()

    # ── CARDS ────────────────────────────────────────────────────────────────
    def _add_card(self, name, dur, path):
        card = RecordingCard(name, dur, path, self._theme)
        card.deleted.connect(self._delete_card)
        self._list_layout.insertWidget(self._list_layout.count() - 1, card)
        self._cards.append(card)
        QTimer.singleShot(50, lambda: self._scroll.verticalScrollBar().setValue(99999))

    def _delete_card(self, card):
        s    = STRINGS[self._lang]
        name = os.path.basename(card.path)
        reply = QMessageBox.question(self, s["dlg_delete_title"],
                                     s["dlg_delete_msg"].format(name),
                                     QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No)
        if reply == QMessageBox.StandardButton.Yes:
            self._list_layout.removeWidget(card)
            card.deleteLater(); self._cards.remove(card)

    # ── TICK ─────────────────────────────────────────────────────────────────
    def _tick(self):
        if self._state == self.REC:
            total = self._elapsed + (time.time() - self._start_ts)
            h, rem = divmod(int(total), 3600); m, s = divmod(rem, 60)
            self._time_lbl.setText(f"{h:02d}:{m:02d}:{s:02d}")
            self._vu.set_level(self._engine.peak_level)

    # ── REFRESH ──────────────────────────────────────────────────────────────
    def _refresh(self):
        s = STRINGS[self._lang]
        t = self._theme

        if self._state == self.IDLE:
            self._status_lbl.setText(s["status_ready"])
            self._status_lbl.setStyleSheet(f"color:{t['text_dim']}; font-family:Courier New; font-size:10pt;")
            self._btn_rec.setText(s["btn_record"])
            self._btn_rec.setEnabled(True)
            self._btn_rec.setStyleSheet(self._btn_style(t["accent"], "white", t["accent"],
                                                         self._darken(t["accent"])))
            self._btn_pau.setEnabled(False)
            self._btn_pau.setText(s["btn_pause"])
            self._btn_pau.setStyleSheet(self._btn_style(t["card"], t["border"], t["card"]))
            self._btn_sav.setEnabled(False)
            self._btn_sav.setText(s["btn_save"])
            self._btn_sav.setStyleSheet(self._btn_style(t["card"], t["border"], t["card"]))

        elif self._state == self.REC:
            self._status_lbl.setText(s["status_recording"])
            self._status_lbl.setStyleSheet(f"color:{t['accent']}; font-family:Courier New; font-size:10pt;")
            self._btn_rec.setText(s["btn_stop"])
            self._btn_rec.setEnabled(True)
            self._btn_rec.setStyleSheet(self._btn_style(t["card"], t["accent"], t["accent"],
                                                         t["border"]))
            self._btn_pau.setEnabled(True)
            self._btn_pau.setText(s["btn_pause"])
            self._btn_pau.setStyleSheet(self._btn_style(t["card"], t["amber"], t["amber"],
                                                         t["border"]))
            self._btn_sav.setEnabled(True)
            self._btn_sav.setText(s["btn_save"])
            self._btn_sav.setStyleSheet(self._btn_style(t["card"], t["green"], t["green"],
                                                         t["border"]))

        elif self._state == self.PAU:
            self._status_lbl.setText(s["status_paused"])
            self._status_lbl.setStyleSheet(f"color:{t['amber']}; font-family:Courier New; font-size:10pt;")
            self._btn_rec.setText(s["btn_stop"])
            self._btn_rec.setEnabled(True)
            self._btn_rec.setStyleSheet(self._btn_style(t["card"], t["accent"], t["accent"],
                                                         t["border"]))
            self._btn_pau.setEnabled(True)
            self._btn_pau.setText(s["btn_resume"])
            self._btn_pau.setStyleSheet(self._btn_style(t["card"], t["green"], t["green"],
                                                         t["border"]))
            self._btn_sav.setEnabled(True)
            self._btn_sav.setText(s["btn_save"])
            self._btn_sav.setStyleSheet(self._btn_style(t["card"], t["green"], t["green"],
                                                         t["border"]))

    @staticmethod
    def _darken(hex_color: str, factor: float = 0.75) -> str:
        c = QColor(hex_color)
        return QColor(int(c.red()*factor), int(c.green()*factor),
                      int(c.blue()*factor)).name()

    # ── HINT / CLOSE ─────────────────────────────────────────────────────────
    def _hint(self):
        s = STRINGS[self._lang]
        QMessageBox.warning(self, s["dlg_install_title"], s["dlg_install_msg"])

    def closeEvent(self, event):
        if self._state != self.IDLE:
            s = STRINGS[self._lang]
            reply = QMessageBox.question(self, s["dlg_close_title"], s["dlg_close_msg"],
                                         QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No)
            if reply != QMessageBox.StandardButton.Yes:
                event.ignore(); return
            self._engine.stop()
        event.accept()


